	HRESULT WriteEventLog(const wchar_t* event_log_msg, unsigned int event_type, long event_id, long product_id)
	{
		return WriteEventLog(event_log_msg, event_type, (product_id != -1) ? (product_id * 1000) + event_id : event_id);
	}

	HRESULT WriteEventLog(const wchar_t* event_log_msg, unsigned int event_type, long event_id)
	{
		return EventLogHelper::WriteEventLog(L"Solimar License Server", event_log_msg, event_type, event_id);
	}

