	/* GetErrorMessage() -  Tries to look up error by looking up IErrorInfo first...
	 *
	 * SLB 18.jun.2025 CR.34040; Fixed issue where FormatMessageW() always returned
	 * E_INVALIDARG so error code was not getting translated.
	 --------------------------------------------------------------------------------*/
	std::wstring GetErrorMessage(
		HRESULT hrErr)
	{
		wchar_t wcsHrErrMsg[256];
		_snwprintf_s(wcsHrErrMsg, _TRUNCATE, L" [0x%08X]", hrErr);
		std::wstring retVal(L"Unknown Error");

		IErrorInfo* pIErrorInfo = NULL;
		if (GetErrorInfo(0, &pIErrorInfo) == S_OK)
		{
			CComBSTR des;
			HRESULT hr;
			hr = pIErrorInfo->GetDescription(&des);
			if (SUCCEEDED(hr))
			{
				retVal = (wchar_t *)des;
				SetErrorInfo(0, pIErrorInfo);
			}
			pIErrorInfo->Release();
		}
		else if (SL_IS_LIC_HR(hrErr))
		{
			//Detect a Solimar License error
			retVal = GetECMessage(SL_EC_FROM_EHR(hrErr));
		}
		else
		{
			HRESULT tempHr = ((hrErr & 0x80070000) == 0x80070000) ? (hrErr & 0x0000FFFF) : hrErr;
			WCHAR * pwcsMsgBuf(NULL);																	// CR.34040; modified.
			DWORD dwRes;
			dwRes = FormatMessageW(
				FORMAT_MESSAGE_ALLOCATE_BUFFER | FORMAT_MESSAGE_FROM_SYSTEM,
				NULL,
				tempHr,
				MAKELANGID(LANG_NEUTRAL, SUBLANG_DEFAULT), // Default language
				reinterpret_cast<LPTSTR>(&pwcsMsgBuf),												// CR.34040; modified.
				0,
				NULL);
			DWORD le(GetLastError());
			if (dwRes != 0)
			{
				std::wstring tempMsg = pwcsMsgBuf;
				// Free the buffer.
				LocalFree(pwcsMsgBuf);

				size_t index(tempMsg.length());
				while (tempMsg[index - 1] == L'\n' || tempMsg[index - 1] == L'\r')
				{
					tempMsg[index] = L'\0';
					index--;
				}
				retVal = std::wstring(tempMsg.substr(0, index));
			}
			le = 0;
		}

		return retVal + ((retVal.find_last_of(L"]") == std::wstring::npos) ? std::wstring(wcsHrErrMsg) : std::wstring(L""));
	}

	// 
	/* GetErrorMessage() -  Tries to look up error by looking up hr in map...
	 *
	 * Special case: if hr == -1; then wsHeaderMsg is used as the main msg.
	 *
	 * SLB 21.may.2025 CR.33769; Did some code refactoring, trying to make code more
	 * understandable to me.
	 * Found code which would never get executed... Removed. It was obsoleted with
	 * file revision 1.38.
	 * SLB 18.jun.2025 CR.34040; Fixed issue where FormatMessageW() always returned
	 * E_INVALIDARG so error code was not getting translated.
	 --------------------------------------------------------------------------------*/
	std::wstring GenerateErrorMessage(
		HRESULT hr, 
		std::wstring wsHeaderMsg, 
		bool bAppendExistingErrorInfo)
	{
		std::wstring wsRetVal(L"Unknown Error");
		std::wstring wsAppendErrorMsg(L"");
		std::wstring wsHeaderErrorMsg(wsHeaderMsg);

		// Figure out what wsRetVal is.
		// Either its passed in wsHeaderMsg or its converted HRESULT into user msg string.
		if (hr == -1)
		{
			wsHeaderErrorMsg = L"";
			wsRetVal = wsHeaderMsg;
		}
		else if (SL_IS_LIC_HR(hr))
		{
			// Detected a Solimar License error
			wsRetVal = GetECMessage(SL_EC_FROM_EHR(hr));
		}
		else
		{
			// Must be a system error code, use FormatMessageW() get the msg string. 
			HRESULT tempHr = ((hr & 0x80070000) == 0x80070000) ? (hr & 0x0000FFFF) : hr;
			WCHAR* pwcsMsgBuf(NULL);																	// CR.34040; modified.
			FormatMessageW(
				FORMAT_MESSAGE_ALLOCATE_BUFFER | FORMAT_MESSAGE_FROM_SYSTEM,
				NULL,
				tempHr,
				MAKELANGID(LANG_NEUTRAL, SUBLANG_DEFAULT), // Default language
				reinterpret_cast<LPTSTR>(&pwcsMsgBuf),												// CR.34040; modified.
				0,
				NULL);
			std::wstring wsTempMsg = pwcsMsgBuf;
			// Free the buffer.
			LocalFree(pwcsMsgBuf);

			size_t index(wsTempMsg.length());
			while (wsTempMsg[index - 1] == L'\n' || wsTempMsg[index - 1] == L'\r')
			{
				wsTempMsg[index] = L'\0';
				index--;
			}
			wsRetVal = wsTempMsg.substr(0, index);
		}

		bool bUseForMainMessage = (_wcsicmp(wsRetVal.c_str(), L"Unknown Error") == 0);
		if (bUseForMainMessage || bAppendExistingErrorInfo)
		{
			IErrorInfo* pIErrorInfo = NULL;
			HRESULT hr = GetErrorInfo(0, &pIErrorInfo);

			if (hr == S_OK)
			{
				CComBSTR bstrDes;
				hr = pIErrorInfo->GetDescription(&bstrDes);
				std::wstring wsDes((const wchar_t*)bstrDes);

				if (SUCCEEDED(hr))
				{
					if (bUseForMainMessage)
						wsRetVal = wsDes;
					else if (bAppendExistingErrorInfo)
					{
						// Only append if message is different. Otherwise, Use the longer 
						// message.
						if (wcsstr(wsDes.c_str(), wsRetVal.c_str()) == NULL)
							wsAppendErrorMsg = wsDes;
						else
							wsRetVal = wsDes;
					}
					SetErrorInfo(0, pIErrorInfo);
				}
				pIErrorInfo->Release();
			}
		}

		std::wstring tmpStr = ((wsHeaderErrorMsg.length() == 0) ? L"" : wsHeaderErrorMsg + L"\r\n - ") +
			wsRetVal +
			((wsAppendErrorMsg.length() == 0) ? L"" : L"\r\n - " + wsAppendErrorMsg);

		CEnterExitMsg::TraceMsg(L"LicMgr::GenerateErrorMessage(): %s", tmpStr.c_str());

		return tmpStr;
	}

	/*
	 *
	 * GetECMessage()
	 *
	 * Looks up a custom Solimar License Error message given the HR error code.
	 */
	std::wstring GetECMessage(unsigned long echr)
	{
		unsigned long ec = echr & 0x0000FFFF;
		for (int i = 0; i < SL_ERROR_COUNT; i++)
		{
			if (SLErrors[i].EC == ec)
				return SLErrors[i].message;
		}
		return SLErrors[0].message; //Unknown
	}

